import { useEffect } from "react";

export const FavIcons = () => {
  useEffect(() => {
    const applyFavicon = () => {
      const dark =
        document.documentElement.getAttribute("data-theme") === "dark";

      const pngLink = document.querySelector<HTMLLinkElement>(
        'link[rel="icon"][type="image/png"]',
      );
      const svgLink = document.querySelector<HTMLLinkElement>(
        'link[rel="icon"][type="image/svg+xml"]',
      );
      const icoLink = document.querySelector<HTMLLinkElement>(
        'link[rel="shortcut icon"]',
      );

      if (pngLink) pngLink.href = dark ? "/favicon-dark.png" : "/favicon-96x96.png";
      if (svgLink) svgLink.href = dark ? "/favicon-dark.png" : "/favicon.svg";
      if (icoLink) icoLink.href = dark ? "/favicon-dark.png" : "/favicon.ico";
    };

    applyFavicon();

    const observer = new MutationObserver(applyFavicon);
    observer.observe(document.documentElement, {
      attributes: true,
      attributeFilter: ["data-theme"],
    });

    return () => observer.disconnect();
  }, []);

  return (
    <>
      <link rel="icon" type="image/png" href="/favicon-96x96.png" sizes="96x96" />
      <link rel="icon" type="image/svg+xml" href="/favicon.svg" />
      <link rel="shortcut icon" href="/favicon.ico" />
      <link rel="apple-touch-icon" sizes="180x180" href="/apple-touch-icon.png" />
      <meta name="apple-mobile-web-app-title" content="CCW" />
      <link rel="manifest" href="/site.webmanifest" />
    </>
  );
};

